 *   freight  : 50 <= weight <= 1000 kg
 *
 * Throws WeightValidationError for weight <= 0 or weight > 1000.
 */
export function classifyWeight(weightKg: number): "standard" | "heavy" | "freight" {
  if (weightKg <= 0 || weightKg > 1000) {
    throw new WeightValidationError(
      `Weight must be greater than 0 and at most 1000 kg, got ${weightKg}`
    );
  }

  if (weightKg < 10) return "standard";
  if (weightKg < 50) return "heavy";
  return "freight";
}

